module edge_detector(
    input clk,
    input reset,
    input signal,
    output reg edge_detected
);

    reg signal_undelayed;

    always @(posedge clk) begin
        if (reset) begin
            signal_undelayed <= 0;
            edge_detected <= 0;
        end else begin
            edge_detected <= signal & ~signal_undelayed;
            signal_undelayed <= signal;
        end
    end

endmodule
